"""
MKT Original Commentary — Deuteronomy 22–25 (96 verses)
Run: python3 scripts/zc-original-deuteronomy-22-25.py
Key decisions:
- 22:7 bird-nest law: 'that it may go well with you' — same life-extension
  promise as honoring parents (Deut 5:16; Eph 6:2-3); mercy toward creation
  as a covenant virtue
- 22:12 tassels/gedilim: Matt 9:20 (woman touching the hem/tzitzit of
  Jesus's garment) is the Deuteronomy 22:12 law in living enactment
- 23:1-8 assembly exclusions: Acts 8 (Ethiopian eunuch) reads as the
  explicit reversal of 23:1 under the new covenant (Isa 56:3-7 bridge)
- 23:3 Moabite exclusion: the single greatest tension with Ruth's inclusion —
  Deut 23:3 is the law Ruth's inclusion appears to violate; the resolution
  is the covenant-loyalty exception implicit in Deuteronomy itself
- 24:1-4 divorce certificate: Matt 19:7-8 cites this directly; Jesus
  intensifies the standard back to creation (Gen 2:24), treating Moses's
  permission as a concession to hard hearts, not the divine ideal
- 24:19-21 gleaning: the legal foundation for Ruth 2; Boaz's allowance
  exceeds the minimum requirement (leaving extra grain for Ruth)
- 25:4 muzzled ox: 1 Cor 9:9 and 1 Tim 5:18 are DIRECT citations; Paul's
  argument that ministers deserve material support rests on this verse
- 25:5-6 levirate marriage: Matt 22:24-28 Sadducees cite this precisely
  in their resurrection riddle; Jesus's response reframes the whole
  framework of marriage and resurrection (Matt 22:30)
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent


def load_comm(layer, book):
    p = ROOT / "data" / "commentary" / layer / f"{book}.json"
    return json.loads(p.read_text()) if p.exists() else {}


def save_comm(layer, book, data):
    p = ROOT / "data" / "commentary" / layer / f"{book}.json"
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=2))


def merge_comm(existing, new_data):
    # INTENT: Write only absent keys so re-running is safe after manual edits.
    # CHANGE? If deuteronomy.json schema changes, update merge_comm and DEUT dict below.
    # VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-original/deuteronomy.json')); print(d.get('22',{}).get('1','MISSING')[:80])"
    for ch, verses in new_data.items():
        existing.setdefault(ch, {})
        for v, text in verses.items():
            existing[ch].setdefault(v, text)


DEUT = {
    "22": {
        "1": "<p>\"You shall not see your brother's ox or his sheep going astray and ignore them (<em>hitalamta</em>, H5956). You shall take them back to your brother\" — <strong>hitalamta</strong> (H5956, to hide oneself, to pretend not to see): the sin of studied inattention to a neighbor's need. The law prohibits not just theft but indifference. The obligation to return lost property extends to all livestock found wandering without their owner, even if the owner is an enemy (Exod 23:4-5 adds the enemy stipulation). The covenant creates an economy of mutual care: the neighbor's loss is my responsibility to remedy. The anti-indifference principle underlies the Good Samaritan parable (Luke 10:30-37: the Levite who \"passed by on the other side\" violates the Deuteronomic spirit).</p>",
        "2": "<p>If the owner is far away or unknown, you shall bring the animal home and keep it until the owner comes looking for it — the burden of temporary stewardship: Israel's law creates a system of responsible custody for lost property rather than the opportunistic appropriation of found goods. The temporary keeping (<em>asafta el-tokh beitecha</em>) is the social infrastructure that assumes community trust and assumed return. The law implicitly prohibits the \"finders keepers\" principle in favor of the \"steward until the owner appears\" principle.</p>",
        "3": "<p>The same law applies to a donkey, a garment, or anything lost by a neighbor — the enumeration broadens the principle beyond livestock to all lost property. The specificity of examples (ox, sheep, donkey, garment, anything) ensures no category of property is exempted by the narrowness of the law's letter. The garment-inclusion is significant: clothing is intimate, personal, and often representing identity — its loss and return is an act of covenant solidarity.</p>",
        "4": "<p>\"You shall not see your brother's donkey or his ox fallen down by the way and ignore them. You shall help him to lift them up\" — the active assistance command: not only return of lost property but physical help with a neighbor's struggling animal. The repetition of <em>hitalamta</em> (hide yourself/ignore) from v1 frames both laws: the prohibition is the same indifferent non-response. The \"lift up with him\" (<em>hakem taqim imo</em>) requires cooperation — this is not a solo task but a communal effort. The double infinitive absolute (<em>hakem taqim</em>) emphasizes the certainty of the obligation.</p>",
        "5": "<p>\"A woman shall not wear a man's garment, nor shall a man put on a woman's cloak, for whoever does these things is an abomination (<em>toevah</em>, H8441) to the LORD your God\" — the boundary legislation: <strong>keli gever</strong> (man's vessel/article) is the broad term for what belongs to the male domain. The <em>toevah</em> term (usually reserved for idolatry and sexual sin) marks this as a boundary violation of high seriousness. The law resists the dissolution of the male-female distinction created in Genesis 1:27 — the sexual differentiation of image-bearers is a creation order that the covenant protects. The specific social context (Canaanite cultic cross-dressing practices in fertility worship) may shape the law's intensity.</p>",
        "6": "<p>\"If you come across a bird's nest in any tree or on the ground, with young ones or eggs and the mother sitting on the young or on the eggs, you shall not take the mother with the young\" — the bird nest law: a remarkably tender environmental-ethical instruction interrupting the surrounding social legislation. The mother bird must be released before taking the young. The law's logic includes: (1) ecological sustainability (not destroying breeding pairs); (2) mercy as a character-forming practice extended to non-human life; (3) the covenant's concern for creation-care built into everyday activity.</p>",
        "7": "<p>\"You shall let the mother go, but the young you may take for yourself, that it may go well with you, and that you may live long\" — <em>lema'an yitav lach veha'arachta yamim</em> (that it may go well with you and you may prolong days): precisely the life-extension promise attached to honoring parents (Deut 5:16; Eph 6:2-3). The parallelism is theologically significant: mercy shown to a mother bird receives the same promised reward as mercy shown to one's mother. The covenant creates a continuity of compassion across the human-animal boundary. Matthew 23:37: \"How often I would have gathered your children together as a hen gathers her chicks under her wings\" — Jesus uses the mother-bird image as the paradigm of his own pastoral desire for Jerusalem, invoking the Deuteronomic mercy-toward-mother-bird in his own mission's framework.</p>",
        "8": "<p>\"When you build a new house, you shall make a parapet for your roof, that you may not bring the guilt of blood upon your house, if anyone should fall from it\" — the building code: a parapet (H4624, <em>maaqeh</em>) on flat roofs prevents accidental death. The law creates personal liability for preventable death: not just murder but negligence that results in death makes one guilty (<em>dam</em>, blood-guilt). The rooftop was a place of daily life in ancient Israelite homes — sleeping, drying grain, social gathering. The safety requirement reflects covenant care for life extended to architecture: your home must not be a hazard to others.</p>",
        "9": "<p>\"You shall not sow your vineyard with two kinds of seed, lest the whole yield be forfeited (<em>tiqdash</em>, H6942), the crop that you have sown and the yield of the vineyard\" — mixed seeds (<em>kil'ayim</em>, H3610, two kinds): the prohibition of mixing is a category-purity principle that runs through Deuteronomy 22 (mixed seeds, mixed yoking, mixed fibers). The rationale is debated: (1) creation-order preservation — each species reproduces after its kind (Gen 1:11-12); (2) symbolic distinction between Israel (YHWH's planting) and the nations (different seeds). The forfeiture consequence (<em>tiqdash</em>, the whole becomes holy/set apart, unusable for common use) makes the violation self-defeating: you lose the entire harvest by mixing.</p>",
        "10": "<p>\"You shall not plow with an ox and a donkey together\" — the mixed-yoking prohibition: two different animals yoked together creates unequal strain (the ox's heavier pull vs. the donkey's lighter trot) and is cruel to the weaker animal. But the law also participates in the same categorical-distinction logic as v9. 2 Corinthians 6:14: \"Do not be unequally yoked with unbelievers.\" Paul's application of the mixed-yoking image to the covenant community's relationships — partnerships, marriages, business — follows the Deuteronomic principle: different kinds functioning under the same yoke create distortion, cruelty, and inefficiency for both.</p>",
        "11": "<p>\"You shall not wear cloth of wool and linen mixed together\" — <em>sha'atnez</em> (H8162, the mixed fabric): another kil'ayim prohibition. Wool (animal-derived) and linen (plant-derived) must not be woven together. The law is one of the <em>chuqqim</em> (statutes without explicitly stated reason) that Deuteronomy preserves from Sinai. The paradox is that the high priest's garments and the tabernacle curtains <em>did</em> use wool and linen together — marking those sacred items as uniquely set apart from the common domain. The prohibition for ordinary Israelites may thus distinguish common life from sacred space.</p>",
        "12": "<p>\"You shall make yourself tassels (<em>gedilim</em>, H1434) on the four corners of the garment with which you cover yourself\" — the tassel command: <em>gedilim</em> (braided/twisted tassels) are the Deuteronomic version of the Numbers 15:38-40 <em>tzitzit</em> with the blue cord (<em>petil tekhelet</em>). The tassels are embodied memory devices: \"you shall see it and remember all the commandments\" (Num 15:39). Matthew 9:20: \"And behold, a woman who had suffered from a discharge of blood for twelve years came up behind him and touched the fringe (<em>kraspedon</em>, LXX translates <em>tzitzit</em> with this word) of his garment.\" The woman's touch of Jesus's <em>tzitzit</em>-tassel is a touch of the covenant sign: she reaches out to the one who embodies the law's fulfillment, and healing flows from that touch. Mark 6:56: crowds begged to touch \"the fringe of his garment\" — the tassel-touch as faith-gesture throughout Jesus's ministry.</p>",
        "13": "<p>\"If any man takes a wife and goes in to her and then hates her and accuses her of misconduct and brings a bad name upon her\" — the beginning of the marriage-dispute legislation (vv13-21): the law creates a judicial process for accusations of non-virginity at marriage. The husband's accusation must be adjudicated by the town elders with specific evidence required. The law protects women from defamation: a false accusation carries penalty (v18-19). The \"bad name\" (<em>shem ra</em>) is a legal concept — damaging someone's reputation requires judicial remedy, not merely social consequence.</p>",
        "14": "<p>\"I did not find this woman to be a virgin\" — the specific accusation. The evidence in question is the \"evidence of virginity\" (<em>betulim</em>, H1331): in the ancient context, the bloodstained cloth from the wedding night preserved as communal proof. The system is deeply embedded in ancient honor-culture practices. The law's purpose is to prevent the arbitrary dismissal or defamation of wives by taking the accusation out of private resolution into judicial process — a protection for women in a context where false accusation could be fatal.</p>",
        "15": "<p>The father and mother shall take the evidence of virginity and bring it to the town elders at the gate — the gate (<em>sha'ar</em>) as judicial space: the city gate is consistently the location of legal proceedings in Israel (Ruth 4:1-12; Amos 5:12,15; Prov 31:23). The evidence is presented to the public authority, not decided privately. The parents' role as advocates for their daughter — bringing the evidence before the elders — is a procedural protection: the woman has legal representation through her family.</p>",
        "16": "<p>\"I gave my daughter to this man to marry, and he hates her\" — the father's advocacy statement. <em>Sane</em> (H8130, hate) in Deuteronomy's marriage laws often functions as a quasi-legal term for the desire to dissolve a marriage (Deut 24:3: \"if the latter man hates her\"). The husband's emotion is a legal category that triggers specific legal consequences: dislike alone does not justify defamation.</p>",
        "17": "<p>\"And now he has accused her of misconduct, saying, 'I did not find your daughter a virgin.' Yet here is the evidence of my daughter's virginity\" — the presentation of evidence. The father's formal challenge: the accusation is legally disputed with physical evidence. The law establishes that accusation must meet counter-evidence; the elder-court adjudicates between the two. The procedural protection prevents naked accusation from carrying automatic legal weight.</p>",
        "18": "<p>Then the elders of that town shall take the man and whip him — the penalty for false accusation: the man who defamed his wife is punished corporally. The whipping and the financial penalty (v19: a hundred shekels of silver to the father) are substantial sanctions. The law's logic is symmetrical to the penalty it would impose if the accusation were true (v21: the woman would die): false accusation of a capital offense receives serious punishment, though not matching in kind.</p>",
        "19": "<p>\"And they shall fine him a hundred shekels of silver and give them to the father of the young woman, because he has brought a bad name upon a virgin of Israel. And she shall be his wife. He may not divorce her all his days\" — the compounded consequence: financial penalty + permanent loss of the right to divorce. The man who weaponized the divorce threat through defamation loses the divorce option entirely. The law creates a permanent bond as both protection for the woman and punishment for the man — an unusual covenant innovation that makes the consequence of the sin the structure of the remedy.</p>",
        "20": "<p>But if the thing is true — evidence of virginity not found — then the woman shall be brought to the door of her father's house and stoned to death — the capital consequence: the woman who entered marriage having violated her betrothal is guilty of the same offense as adultery (because betrothal was legally binding in Israel — cf. Matt 1:18-19: Joseph's discovery before their marriage required a \"divorce\" certificate to end the betrothal). The severity reflects the covenant's understanding of sexual faithfulness as a covenant matter, not merely a personal choice.</p>",
        "21": "<p>\"She has done an outrageous thing (<em>nevalah</em>, H5039) in Israel by whoring in her father's house\" — <strong>nevalah</strong> (H5039, outrage/disgrace): a term for acts that violate the social-ethical fabric of the covenant community in a deeply destructive way. The same term is used for Dinah's rape (Gen 34:7), the Gibeah gang-rape (Judg 19:23), Amnon's rape of Tamar (2 Sam 13:12). The father's house is the domain of covenantal oversight: the violation happened under the father's responsibility. \"So you shall purge the evil from your midst\" (<em>uvi'arta hara miqirbecha</em>) — the standard Deuteronomic formula for removing covenant-corrupting sin from the community.</p>",
        "22": "<p>\"If a man is found lying with the wife of another man, both of them shall die, the man who lay with the woman, and the woman\" — the adultery law: both parties receive equal penalty. The symmetrical punishment contrasts with ancient Near Eastern laws that typically punished only the woman. Deuteronomy's equal application prevents the law from being used as a tool of gender-selective punishment. Jesus in John 8:1-11 (the woman caught in adultery): the Pharisees bring only the woman, violating the Deuteronomic symmetry — the absent man is itself a problem with their application. Jesus's response (\"let the one without sin cast the first stone\") is consistent with the law's requirement for dual-guilt prosecution.</p>",
        "23": "<p>\"If there is a betrothed virgin, and a man meets her in the city and lies with her\" — the rape-or-consensual-sex-in-city law: the legal presumption when the encounter occurs in the city is that the woman could have called for help and did not. The presumption of urban accessibility to help creates the legal inference of consent when no cry was raised. The law is making a probabilistic legal inference, not a moral judgment about all possible scenarios — it establishes the burden of evidence for determining consent in the pre-forensic legal context.</p>",
        "24": "<p>Both shall be brought to the gate of the city and stoned to death — in the city scenario: both guilty, both sentenced. \"The young woman because she did not cry for help though she was in the city, and the man because he violated his neighbor's wife\" — the parallel guilt structure. The man's guilt is defined as violation of the neighbor's wife (covenant violation of another man's exclusive marital right). The law's logic is culturally embedded in the honor-community framework, but its concern for protecting the betrothed woman is its ethical core.</p>",
        "25": "<p>\"But if in the open country a man meets a young woman who is betrothed, and the man seizes her and lies with her, then only the man who lay with her shall die\" — the rural rape scenario: only the man is guilty. The absence of potential witnesses and the inability to call for help means the woman is presumed innocent. The law's context-sensitivity creates the non-consensual/consensual distinction through geographic inference — a primitive but genuine attempt to adjudicate rape versus consensual sex in a legal system without forensic evidence.</p>",
        "26": "<p>\"But you shall do nothing to the young woman; she has committed no offense punishable by death\" — the explicit innocence declaration: <em>ein lana'ar chet mavet</em> (there is no sin of death in the young woman). The legal protection of the rape victim from punishment is explicit and important. The law analogizes to murder: a man who attacks another in a field has no witnesses; the attacked person is the victim. The analogy asserts the rural rape victim is the equivalent of a murder victim — the party against whom the offense is committed, not a participant in the offense.</p>",
        "27": "<p>\"For he found her in the open country, and though the betrothed young woman cried for help there was no one to rescue her\" — the assumed-cry inference: in the rural case, the law assumes the cry for help was made even though no one heard it. The legal system extends benefit of the doubt to the woman in the rural scenario: absence of witnesses to a cry does not prove the absence of a cry. The asymmetry between the city and country rulings shows the law making probabilistic rather than moralistic inferences.</p>",
        "28": "<p>\"If a man meets a virgin who is not betrothed, and seizes her and lies with her, and they are found\" — the non-betrothed virgin rape: a different legal scenario with a different outcome. This case involves a woman with no existing marital claim — the legal consequence differs from the adultery-adjacent betrothal cases above.</p>",
        "29": "<p>Then the man shall give fifty shekels of silver to the father and she shall be his wife, and he may not divorce her all his days, because he has violated her — the non-betrothed rape resolution: marriage + fine, no right to divorce. The law is criticized as punishing the victim through mandatory marriage to her rapist. Its ancient context: the law protected the woman from social destitution (an unmarried non-virgin had few options in the ancient world) by requiring the man to provide permanent marital support. The no-divorce provision protects her from a second abandonment after violation. The law is not an ideal but a protection within a specific cultural-economic context.</p>",
        "30": "<p>\"A man shall not take his father's wife, so that he does not uncover his father's nakedness\" — the incest prohibition: the father's wife (stepmother or secondary wife) is covered by the same uncovering-prohibition as Leviticus 18:8. <em>Gilah kenaf aviv</em> — uncovering the corner/wing of his father. 1 Corinthians 5:1-5: Paul addresses the Corinthian case of a man living with his father's wife as requiring excommunication — \"a kind of sexual immorality that is not tolerated even among pagans.\" Paul's application of Deuteronomy's standard to the Gentile church shows the torah-principle operating as moral baseline even in the new covenant context.</p>"
    },
    "23": {
        "1": "<p>\"No one whose testicles are crushed or whose male organ is cut off shall enter the assembly of the LORD\" — the eunuch exclusion: <em>qehal YHWH</em> (the assembly of YHWH) is the covenant community's formal gathering. The exclusion of those with injured reproductive organs from the assembly reflects an ancient holiness-boundary: the assembly of YHWH required wholeness (<em>shalom</em>) reflecting the integrity of image-bearing. Isaiah 56:3-5 explicitly reverses this for the new covenant era: \"Let not the eunuch say, 'Behold, I am a dry tree.' For thus says the LORD: 'To the eunuchs who keep my sabbaths... I will give them an everlasting name.'\" Acts 8:26-39: the Ethiopian eunuch's baptism by Philip is the enacted fulfillment of Isaiah 56's reversal — the excluded are included in the new covenant assembly.</p>",
        "2": "<p>\"No one born of a forbidden union (<em>mamzer</em>, H4464) shall enter the assembly of the LORD. Even to the tenth generation, none of his descendants may enter the assembly of the LORD\" — the <em>mamzer</em> exclusion: <strong>mamzer</strong> (H4464) is debated — it may mean the product of an incestuous or prohibited union (the rabbinic definition) rather than simply a child of unmarried parents. The ten-generation exclusion is the longest exclusion in the assembly-laws. The NT's gracious paradox: the genealogy of Jesus in Matthew 1 includes Perez (son of Judah and Tamar's union, arguably a <em>mamzer</em>-category union), Rahab (Canaanite prostitute), and Ruth (Moabite) — precisely the categories Deuteronomy 23 most severely excludes. The Messiah's genealogy deliberately includes the most excluded.</p>",
        "3": "<p>\"No Ammonite or Moabite may enter the assembly of the LORD. Even to the tenth generation, none of them may enter the assembly of the LORD forever\" — the Ammonite/Moabite exclusion: the reason follows in v4 (they did not meet Israel with bread and water, and they hired Balaam against Israel). The perpetual exclusion of these two Lot-descended peoples creates the greatest tension in the Hebrew Bible: Ruth the Moabite becomes the great-grandmother of David (Ruth 4:17), and Matthew includes her in the Messiah's line (Matt 1:5). The resolution in Ruth is covenant-loyalty (Ruth's <em>chesed</em> toward Naomi) transcending ethnic boundary — Deut 23:3's exclusion applies to national Israel as a polity, while Ruth's individual covenant loyalty grants individual exception. The tension itself is theologically productive: it demonstrates the covenant can both exclude and include by the same logic of faithfulness.</p>",
        "4": "<p>\"Because they did not meet you with bread and water on the way, when you came out of Egypt, and because they hired against you Balaam the son of Beor from Pethor of Mesopotamia, to curse you\" — the historical grounds for exclusion: (1) failure of hospitality at Israel's most vulnerable moment; (2) active hostility through hiring Balaam. Both are covenant-breaking behaviors against a people to whom they had kinship obligation. The grounds-based exclusion differs from ethnic prejudice: the exclusion is punitive for specific historical acts, not ontological.</p>",
        "5": "<p>\"But the LORD your God would not listen to Balaam; instead the LORD your God turned the curse into a blessing for you, because the LORD your God loved you\" — the Balaam reversal: YHWH transformed the attempted curse into blessing (Num 22-24). The specific act that grounds Moab's exclusion (hiring Balaam) was already overturned by YHWH's intervention. The exclusion stands despite the failed curse — the intent, not only the effect, warranted the consequence. This passage about Balaam is the background for 2 Peter 2:15 and Jude 11 (\"Balaam's error\") and Revelation 2:14 (\"teaching of Balaam\") — the Balaam tradition becomes NT shorthand for false teaching motivated by financial gain.</p>",
        "6": "<p>\"You shall not seek their peace or their prosperity all your days forever\" — the non-treaty command regarding Ammon and Moab: Israel is not to pursue covenant-alliance with these two nations. The political-theological logic: nations that used their relationship with Israel for hostile purposes cannot be trusted as alliance partners. The rule limits the covenant community's diplomatic options but protects it from repeating the vulnerability that Balaam's hiring exploited.</p>",
        "7": "<p>\"You shall not abhor an Edomite, for he is your brother. You shall not abhor an Egyptian, because you were a sojourner in his land\" — the contrasting non-exclusions: Edom (Esau's descendants, Jacob's brother) and Egypt (Israel's former slaveholder) receive partial welcome despite historical grievances. The Edomite inclusion reflects the Jacob-Esau brotherhood. The Egyptian inclusion is remarkable: despite 430 years of enslavement, Israel is commanded not to abhor (<em>teta'ev</em>) Egyptians. The Exodus was YHWH's act against Pharaoh, not a warrant for permanent hatred of Egyptians.</p>",
        "8": "<p>\"Children born to them in the third generation may enter the assembly of the LORD\" — the Edomite and Egyptian integration timeline: three generations, not ten (as for Ammon/Moab) or forever (as for the <em>mamzer</em>). The graduated inclusion periods reflect the graduated severity of past hostility: Egypt's slavery is treated as less permanently disqualifying than Ammon/Moab's active cursing-conspiracy. The law models a principle of proportional exclusion with defined re-integration pathways.</p>",
        "9": "<p>\"When you are encamped against your enemies, you shall keep yourself from every evil thing\" — the camp-holiness section (vv9-14): the military camp must meet the same holiness standards as the sanctuary. YHWH's presence in the war-camp (v14) requires the same ritual purity that his presence in the tabernacle requires. The logic: the God who fights with Israel fights from within the camp; his presence sanctifies the entire camp as sacred space. The military and the sacred are not separate domains in Israel's covenant theology.</p>",
        "10": "<p>\"If any man among you becomes unclean because of a nocturnal emission, then he shall go outside the camp. He shall not come inside the camp\" — the ritual impurity in camp legislation: the holiness-boundary applies to bodily emissions that create temporary ritual impurity (Lev 15:16-18). The temporary exclusion is not shame but hygiene-of-holiness: the emission creates a state incompatible with the divine presence in the camp. The exclusion is temporary and remedied by washing and waiting for evening (v11).</p>",
        "11": "<p>\"But when evening comes, he shall bathe himself in water, and when the sun sets, he may come inside the camp\" — the restoration procedure: washing + time (evening). The same restoration sequence appears throughout Leviticus 15 for various emissions. The regular restoration path ensures that the exclusion is temporary and that full participation in the covenant community is the expected outcome. No permanent exclusion for ritual impurity; the covenant provides for return.</p>",
        "12": "<p>\"You shall have a place outside the camp, and you shall go out to it\" — the latrine legislation: perhaps the most physically practical law in the Torah. Sanitation outside the camp is a public-health requirement that also carries theological significance (v14: YHWH \"walks\" in the camp). The law integrates the practical and the theological: even bodily waste disposal is a covenant matter when YHWH is present.</p>",
        "13": "<p>\"And you shall have a trowel with your tools, and when you sit down outside, you shall dig a hole with it and turn back and cover up your excrement\" — the specific sanitation instruction: carry a tool, dig, cover. The precision of the command is striking — this is Moses legislating field-latrine practice, and the law is in the Torah. Covenant life is embodied, physical, and total: nothing is too mundane for covenant concern.</p>",
        "14": "<p>\"Because the LORD your God walks in the midst of your camp, to deliver you and to give up your enemies before you, therefore your camp must be holy, so that he may not see anything indecent among you and turn away from you\" — the theological ground for camp sanitation: YHWH walks (<em>mithalech</em>) in the camp — the same verb used of his walking in the Garden (Gen 3:8). His presence in the camp is the Edenic presence extended to the wilderness community. The <em>erva</em> (indecency/nakedness) he must not see is the general category of what dishonors the divine presence. 2 Corinthians 6:16: \"For we are the temple of the living God; as God said, 'I will make my dwelling among them and walk among them.'\" The walking-God-in-the-camp is the paradigm that Paul applies to the church as YHWH's new dwelling-place.</p>",
        "15": "<p>\"You shall not give up to his master a slave who has escaped from his master to you\" — the escaped slave sanctuary law: a remarkable humanitarian provision. The escaped slave who reaches Israel is not to be returned. The law inverts the common ancient Near Eastern practice (typically slaves were returned under treaty). The ground is implicit: Israel was enslaved in Egypt and YHWH liberated them; they cannot be instruments of returning others to slavery. Philemon: Paul's letter to Philemon regarding Onesimus (the escaped slave) navigates this territory with apostolic tact — appealing rather than commanding, but the Deuteronomic precedent for sanctuary is the background to Paul's plea.</p>",
        "16": "<p>\"He shall dwell with you, in your midst, in the place that he shall choose within any of your towns, wherever it suits him. You shall not wrong him\" — the escaped slave's full community membership: not just asylum but integration. The slave lives where he chooses, not where the community assigns him. The no-wronging command (<em>lo tonenu</em>) parallels the alien-protection commands (Exod 22:21; Lev 19:33) — the escaped slave receives the same legal protection as the native Israelite. The covenant community becomes a zone of freedom for the formerly enslaved.</p>",
        "17": "<p>\"None of the daughters of Israel shall be a cult prostitute (<em>qedeshah</em>, H6948), and none of the sons of Israel shall be a cult prostitute (<em>qadesh</em>, H6945)\" — the cultic prostitution prohibition: <strong>qedeshah</strong> (female) and <strong>qadesh</strong> (male) are related to <em>qadosh</em> (holy/set apart). The terms may refer to persons dedicated to the Canaanite fertility-deity cult whose sexual service was considered worship. The law prohibits Israelites from this practice absolutely: the sexual body is not a vehicle of pagan worship. 1 Corinthians 6:15-20: \"Do you not know that your bodies are members of Christ himself? Shall I then take the members of Christ and unite them with a prostitute?... your body is a temple of the Holy Spirit.\" Paul's argument adapts the Deuteronomic prohibition to the new covenant context: sexual immorality defiles the Spirit-indwelt body that is now YHWH's sanctuary.</p>",
        "18": "<p>\"You shall not bring the fee of a prostitute or the wages of a dog (<em>kelev</em>, H3611) into the house of the LORD your God in payment for any vow, for both of these are an abomination to the LORD your God\" — the tainted-money prohibition: income from prostitution cannot be sanctified by temple offering. <em>Kelev</em> (dog) may be a derogatory term for the male cult-prostitute (the qadesh of v17). The law prevents the attempt to launder profane income through sacred donation. The logic: the offering must come from honest labor; tainted income taints the offering. The principle extends to all attempts to use religious giving as moral whitewash for exploitative practices.</p>",
        "19": "<p>\"You shall not charge interest (<em>neshech</em>, H5392) on loans to your brother, interest on money, interest on food, interest on anything that is lent for interest\" — the interest prohibition within the covenant community: <strong>neshech</strong> (H5392, interest, lit. a bite) is prohibited between Israelites but permitted with foreigners (v20). The brother-covenant creates an economic ethics different from market ethics: the covenant community is not to profit from each other's poverty. Psalm 15:5: the person who \"lends money without interest\" is described as one who \"will never be shaken.\" Ezekiel 18:8 includes non-interest lending in the profile of the righteous man. The NT applies the ethic broadly: Luke 6:35: \"lend, expecting nothing in return.\"</p>",
        "20": "<p>\"You may charge a foreigner interest, but you may not charge your brother interest, that the LORD your God may bless you in all that you undertake in the land\" — the distinction between covenant-community economics and market economics: the foreigner exists in a market relationship with Israel; the brother exists in a covenant relationship. The blessing-promise tied to the non-interest practice: generosity within the covenant creates the conditions for YHWH's blessing. The economic ethics of the covenant is not universalized to all economic relations in this law but intensified within the family-of-God relationship.</p>",
        "21": "<p>\"If you make a vow to the LORD your God, you do not delay fulfilling it, for the LORD your God will surely require it of you, and you will be guilty of sin\" — the vow-keeping imperative: <em>neder</em> (H5088, vow) to YHWH is legally binding and time-sensitive. Delay (<em>lo te'acher lishalmo</em>) is itself a sin. Ecclesiastes 5:4-5: \"When you vow a vow to God, do not delay paying it... It is better that you should not vow than that you should vow and not pay.\" Matthew 5:37: \"Let what you say be simply 'Yes' or 'No'; anything more than this comes from evil.\" Jesus's teaching on oaths and vows intensifies Deuteronomy 23:21 — the covenant person's word should be so reliable that no vow is needed; the casual vow-making that requires the Deuteronomic law reflects the problem of the gap between speaking and meaning.</p>",
        "22": "<p>\"But if you refrain from vowing, you will not be guilty of sin\" — the permissive non-vow option: vowing is voluntary, not required. Deuteronomy does not mandate vow-making; it only requires that vows made be kept. The prudential logic: better not to vow than to vow and default. The silence of the law regarding the content of appropriate vows leaves the Nazirite vow (Num 6) and other specific vow-forms as optional acts of devotion, not universal requirements.</p>",
        "23": "<p>\"You shall be careful to do what has passed your lips, for you have voluntarily vowed to the LORD your God what you have promised with your mouth\" — the emphasis on personal initiative and binding speech: <em>motzah sefatecha tishmor</em> (what goes out from your lips you shall keep). The vow is self-imposed (<em>nedavah</em>, freewill offering context) and therefore absolutely binding. The combination of voluntariness and bindingness reflects the covenant's understanding of speech: words once spoken create obligations. The God who speaks and it is done (Gen 1) expects his covenant people to reflect his own speech-integrity.</p>",
        "24": "<p>\"If you go into your neighbor's vineyard, you may eat your fill of grapes, as many as you wish, but you shall not put any in your bag\" — the vineyard-grazing permission: travelers may eat on the spot but may not take quantities away. The law balances hospitality (the open vineyard for the hungry traveler) with property rights (no bulk removal). This is the legal background for Mark 2:23 (the disciples plucking heads of grain on the Sabbath): they were permitted to pluck and eat (Deut 23:24-25) but the Pharisees objected to the timing (Sabbath). The law itself permitted what they were doing; the controversy was about when.</p>",
        "25": "<p>\"If you go into your neighbor's standing grain, you may pluck the ears with your hand, but you shall not put a sickle to your neighbor's standing grain\" — the field-grazing permission: hand-plucking permitted, no harvest tools. The same provision that authorizes the disciples' Sabbath-walk gleaning (Mark 2:23 parallel). The law creates what might be called a minimal-hospitality floor: the hungry traveler has a legal right to eat from another's field without payment, but not to appropriate a crop. This minimal-hospitality right is one of several in Deuteronomy (gleaning laws in 24:19-21) that construct a safety net for the vulnerable within the covenant community.</p>"
    },
    "24": {
        "1": "<p>\"When a man takes a wife and marries her, if then she finds no favor in his eyes because he has found some indecency (<em>ervat davar</em>, H1320+H6961) in her, and he writes her a certificate of divorce (<em>sefer keritut</em>, H5612+H3748) and puts it in her hand and sends her out of his house\" — the divorce legislation: <strong>ervat davar</strong> (\"nakedness of a thing\" / \"indecency of a matter\") became the great point of rabbinic debate — the Shammai school interpreted it strictly (sexual immorality only) while the Hillel school interpreted it broadly (any displeasing thing). <strong>Sefer keritut</strong> (document of cutting-off): the written certificate provided legal protection — the divorced woman could remarry (v2) and was not subject to punishment as an adulteress. Matthew 19:7-8: Jesus is asked about this law by the Pharisees; he responds that Moses permitted divorce \"because of your hardness of hearts, but from the beginning it was not so\" — setting Gen 2:24 (one flesh) as the creation-ideal above Deut 24:1 as the concession-to-sin.</p>",
        "2": "<p>\"And if she goes and becomes another man's wife\" — the remarriage permission for the divorced woman. The certificate of divorce enables legal remarriage without the stigma of adultery. The divorced woman has full freedom to remarry: the certificate restores her to the legal status of an unmarried woman regarding future marriage.</p>",
        "3": "<p>\"And the latter man hates her and writes her a certificate of divorce and puts it in her hand and sends her out of his house, or if the latter man dies, who took her to be his wife\" — the second divorce or death scenario creates the situation the law is actually addressing (v4): the original husband cannot take her back.</p>",
        "4": "<p>\"Then her former husband, who sent her away, may not take her again to be his wife, after she has been defiled (<em>hutamma'ah</em>), for that is an abomination before the LORD. And you shall not bring sin upon the land that the LORD your God is giving you for an inheritance\" — the re-marriage prohibition: the first husband cannot remarry his twice-divorced-or-widowed wife. The defilement language (<em>tame</em>, ritual impurity) applies to the changed covenant status: the first marriage has been legally severed and a second has intervened. The re-marriage would constitute a form of disguised divorce-and-remarriage cycle that the law prevents as prostitution-by-marriage-rotation. Jeremiah 3:1 uses this law as a metaphor for Israel's relationship with YHWH: \"If a man divorces his wife and she goes and becomes another man's wife, will he return to her?\"</p>",
        "5": "<p>\"When a man is newly married, he shall not go out with the army or be liable for any other public duty. He shall be free at home one year to be happy with his wife whom he has taken\" — the newlywed exemption: one year of home-freedom from military service. The legal protection of the marriage's foundation: the new covenant between husband and wife requires a full year of undistracted establishment. The law reflects a wisdom about human relationships: the early period of a marriage is formative, and disrupting it with military absence before the relationship is established is destructive. The one-year honeymoon protected by law is a striking humanitarian provision within ancient military culture.</p>",
        "6": "<p>\"No one shall take a mill or an upper millstone in pledge, for that would be taking a life in pledge\" — the millstone prohibition: the upper and lower millstones are the household's daily bread-production equipment. Taking them as loan collateral deprives the family of their basic livelihood. <em>Ki nefesh hu chovel</em> (for it is a life he is taking as pledge): the millstone represents life itself — the daily bread. The law creates a category of basic-livelihood items exempt from pledging. The principle underlies the broader collateral-law tradition (vv12-13, 17) that protects the vulnerable from having their survival-tools taken as security.</p>",
        "7": "<p>\"If a man is found stealing one of his brothers of the people of Israel, and if he treats him as a slave or sells him, then that thief shall die. So you shall purge the evil from your midst\" — the kidnapping law: man-stealing is a capital offense. The same crime is mentioned in the Decalogue's context (Exod 20:15; the commandment \"you shall not steal\" may originally have referred to man-stealing before being generalized). The kidnap-and-enslave crime attacks the fundamental freedom that YHWH granted Israel at the Exodus. The phrase <em>vehi'thamer bo umekaro</em> (treats him as a slave and sells him) describes the full commodification of a person, which is the extreme of covenant violation.</p>",
        "8": "<p>\"Take care, in a case of leprous disease, to be very careful to do according to all that the Levitical priests shall direct you. As I commanded them, so you shall be careful to do\" — the priestly authority over skin-disease diagnosis: the full legislation is in Leviticus 13-14. Deuteronomy's reference is a cross-pointer. The priesthood's diagnostic role in infectious-skin-disease cases maintained public health through ritual segregation and reintegration protocols. The Levitical priests are the public-health authority for the covenant community.</p>",
        "9": "<p>\"Remember what the LORD your God did to Miriam on the way as you came out of Egypt\" — the Miriam-memory as warning: Miriam's leprous judgment (Num 12:1-15) is cited as the reason for taking skin-disease laws seriously. The reference serves as a precedent-reminder: even Moses's sister, even a prophetess, faced divine judgment for covenant violation while the disease-law was active. The memory is meant to induce carefulness, not shame: these laws are not arbitrary but reflect YHWH's holiness enacted in communal health protection.</p>",
        "10": "<p>\"When you make your neighbor a loan of any sort, you shall not go into his house to collect his pledge\" — the creditor's entry-prohibition: the lender may not enter the debtor's home to retrieve the pledge. The debtor brings out what he offers. The law protects the debtor's domestic privacy and dignity: the creditor has no right to search the home. The subtle honor-protection of the poor person's household space prevents the creditor from surveilling and controlling the debtor's living conditions.</p>",
        "11": "<p>\"You shall stand outside, and the man to whom you make the loan shall bring the pledge out to you\" — the procedure: the debtor chooses what to offer as pledge, within the constraints of the law (no millstone, v6). The debtor retains agency over what enters the pledge-relationship. The protocol normalizes the creditor-debtor relationship without dehumanizing the debtor: the loan is a service, not leverage for total control.</p>",
        "12": "<p>\"And if he is a poor man, you shall not sleep in his pledge\" — the overnight-cloak rule: if the poor person's only pledge is his garment (cloak), the creditor must return it before nightfall. The cloak serves as bedding for the poor person sleeping outside. The creditor's right to pledge is subordinated to the debtor's right to sleep in warmth. Amos 2:8: \"they lay themselves down beside every altar on garments taken in pledge\" — the prophetic condemnation echoes this law's violation.</p>",
        "13": "<p>\"You shall restore to him the pledge as the sun sets, that he may sleep in his cloak and bless you. And it shall be righteousness for you before the LORD your God\" — the righteousness-reward: returning the cloak at sunset is credited to the creditor as <em>tzedaqah</em> (H6666, righteousness). The charitable loan-management is covenant faithfulness that YHWH recognizes. The poor man's blessing (<em>veberachecha</em>) is not merely sentiment but a covenantal act: his gratitude is a form of covenant witness that YHWH honors.</p>",
        "14": "<p>\"You shall not oppress a hired worker who is poor and needy, whether he is one of your brothers or one of the sojourners who are in your land within your towns\" — the wage-laborer protection: <em>lo tashaq</em> (do not oppress/wrong). The prohibition extends to both Israelite and alien hired workers — the alien receives the same protection within Israel's borders. The economic vulnerability of the day-laborer (who depends on immediate payment for that day's survival) creates a specific obligation for the employer. James 5:4: \"Behold, the wages of the laborers who mowed your fields, which you kept back by fraud, are crying out against you.\"</p>",
        "15": "<p>\"You shall give him his wages on the same day, before the sun sets (for he is poor and counts on it), lest he cry out against you to the LORD, and you be guilty of sin\" — same-day wage payment: the urgency is the worker's economic reality — <em>ki ani hu ume'elav nefesh nasa</em> (for he is poor and to it his soul is lifted up / he is counting on it for his life). The cry (<em>qara</em>) of the unpaid worker before YHWH is a claim YHWH hears: the unpaid wage is treated as a covenant violation with divine consequences for the employer. Leviticus 19:13 parallels the command.</p>",
        "16": "<p>\"Fathers shall not be put to death because of their children, nor shall children be put to death because of their fathers. Each one shall be put to death for his own sin\" — <strong>ish bekheto yumatu</strong> (each shall die for his own sin): individual moral and legal responsibility. This verse establishes one of the most important principles of justice: no corporate punishment for individual sin, no family-wide execution for one member's crime. Jeremiah 31:29-30 and Ezekiel 18 develop this principle prophetically against the proverb \"the fathers have eaten sour grapes and the children's teeth are set on edge.\" The new covenant's individual-responsibility emphasis (Ezek 18:20: \"the soul who sins shall die\") is grounded in Deuteronomy 24:16. Romans 14:12: \"each of us will give an account of himself to God.\"</p>",
        "17": "<p>\"You shall not pervert the justice due to the sojourner or to the fatherless, or take a widow's garment in pledge\" — the vulnerable-person justice mandate: three groups receive specific protection — the sojourner (alien), the fatherless, and the widow. These three form the recurring triad of the socially vulnerable in Israel's covenant ethics (Deut 10:18; 14:29; 16:11,14; 27:19; Isa 1:17; Jer 7:6; Zech 7:10). Their vulnerability is their legal protection: YHWH is their advocate, and perverting their justice is direct opposition to YHWH's own character (Deut 10:18: \"he executes justice for the fatherless and the widow\").</p>",
        "18": "<p>\"You shall remember that you were a slave in Egypt and the LORD your God redeemed you from there; therefore I command you to do this\" — the Egypt-memory as ethical foundation: the ground for protecting the vulnerable is Israel's own vulnerability-history. The Exodus experience creates permanent ethical obligation: those whom YHWH redeemed from vulnerability must not re-create vulnerability for others. The memory is not nostalgic but formative: Israel's identity as the redeemed determines their ethical obligations as the community of the redeemed.</p>",
        "19": "<p>\"When you reap your harvest in your field and forget a sheaf in the field, you shall not go back to get it. It shall be for the sojourner, the fatherless, and the widow, that the LORD your God may bless you in all the work of your hands\" — the forgotten-sheaf law: <em>liqet</em> (H3950, gleaning). The forgotten sheaf must be left for the vulnerable triad. The law institutionalizes generosity by prohibiting the retrieval of accidentally left-behind produce. The book of Ruth dramatizes this law: Ruth gleans in Boaz's field under this legal provision (Ruth 2:2-3,15-17), and Boaz exceeds the minimum by instructing his workers to leave extra (Ruth 2:16). The gleaning law is the legal infrastructure of the love-story between Ruth and Boaz.</p>",
        "20": "<p>\"When you beat your olive trees, you shall not go over them again. It shall be for the sojourner, the fatherless, and the widow\" — the olive-harvest leftover: after the beating-harvest (knocking olives from branches), the remaining olives on the highest branches must be left. The three-vulnerability-triad receives equal protection across grain (v19), olive (v20), and grape (v21) harvests. The systematic inclusion of all three major agricultural products ensures the vulnerable have a legal claim across the full harvest cycle.</p>",
        "21": "<p>\"When you gather the grapes of your vineyard, you shall not strip it afterward. It shall be for the sojourner, the fatherless, and the widow\" — the vineyard-gleaning law: after the main grape harvest, the remaining clusters must be left. The entirety of the agricultural economy is structured so that the vulnerable have legal access to a portion of every harvest. This is the institutionalized generosity of the covenant economy: not charity as an optional virtue but legal obligation built into harvest practice.</p>",
        "22": "<p>\"You shall remember that you were a slave in the land of Egypt; therefore I command you to do this\" — the Egypt-memory refrain concludes the gleaning laws as it concluded the wage law (v18). The repetition is structural: the entire social-welfare section of Deuteronomy 24 is framed by the slave-in-Egypt memory. Israel's identity as the liberated people requires them to structure their economy so that the vulnerable among them experience what Israel experienced from YHWH: provision in vulnerability, rescue from want. The gleaning laws are the economic embodiment of the Exodus story.</p>"
    },
    "25": {
        "1": "<p>\"If there is a dispute between men and they come into court and the judges decide between them, acquitting the innocent (<em>tzadiq</em>) and condemning the guilty (<em>rasha</em>)\" — the judicial process premise: the court (<em>mishpat</em>) functions by distinguishing the righteous from the wicked. <em>Tzaddiq</em> and <em>rasha</em> are not merely legal categories (innocent/guilty) but covenant categories: the righteous one lives in covenant faithfulness; the wicked one violates it. The court is the institution that aligns legal outcomes with covenant reality. Romans 3:4: \"that you may be justified in your words and prevail when you are judged\" — the Psalmic pattern of YHWH as the righteous judge is the ground of the human judicial system.</p>",
        "2": "<p>\"Then if the guilty man deserves to be beaten, the judge shall cause him to lie down and be beaten in his presence with a number of stripes in proportion to his offense\" — the corporal punishment law: the flogging (<em>makah</em>) must occur in the judge's presence (preventing private revenge or excessive punishment), must be proportional to the offense, and is subject to the limit that follows. The judge's presence at the punishment is a procedural protection: the punishment is a judicial act, not a social one. 2 Corinthians 11:24: Paul reports receiving \"forty lashes less one\" five times from Jewish authorities — showing that Deuteronomy 25:2-3's legal punishment was actively administered in the Second Temple period.</p>",
        "3": "<p>\"Forty stripes may be given him, but not more, lest, if one should go on to beat him with more stripes than these, your brother be degraded in your sight\" — the forty-stripe maximum: the limit protects human dignity. <em>venikleh achikha le'einecha</em> (lest your brother be degraded before your eyes): the convict remains a <em>brother</em> even during punishment — the covenant brotherhood is not dissolved by wrongdoing. The maximum is not an optimal punishment but a dignity-floor that legal punishment cannot breach. Jewish practice implemented it as \"forty less one\" (39) to prevent accidental breach of the limit (hence Paul's \"forty lashes less one\").</p>",
        "4": "<p>\"You shall not muzzle an ox when it is treading out the grain\" — the ox-muzzle prohibition: <em>lo tachsom shor bedisho</em>. The ox working to thresh grain is allowed to eat from the grain it processes. 1 Corinthians 9:9: \"For it is written in the Law of Moses, 'You shall not muzzle an ox when it treads out the grain.' Is it for oxen that God is concerned?\" 1 Timothy 5:18: \"For the Scripture says, 'You shall not muzzle an ox when it treads out the grain,' and, 'The laborer deserves his wages.'\" Paul's application: DIRECT citation, with explicit hermeneutical move — if even working animals deserve to eat from their labor, how much more do human ministers deserve material support from those they serve. The principle (labor generates right to support) transcends the specific application (ox in grain) and applies to the more-than-ox minister of the gospel.</p>",
        "5": "<p>\"If brothers dwell together, and one of them dies and has no son, the wife of the dead man shall not be married outside the family to a stranger. Her husband's brother shall go in to her and take her as his wife and perform the duty of a husband's brother to her\" — the levirate marriage law (<em>yibbum</em>, from <em>yavam</em>, H2992, husband's brother): the brother-in-law takes the dead brother's widow as wife to produce offspring that will carry the dead brother's name and inheritance. <strong>Levirate</strong> is from Latin <em>levir</em> (husband's brother). Matthew 22:24-28: the Sadducees pose the levirate-marriage scenario (a woman successively married to seven brothers) as a reductio ad absurdum against resurrection. Jesus's response (\"in the resurrection they neither marry nor are given in marriage, but are like angels in heaven\") does not abandon levirate law but reframes the eschatological situation: resurrection existence transcends the social-economic-kinship framework within which levirate marriage was necessary.</p>",
        "6": "<p>\"And the firstborn son whom she bears shall succeed to the name of his dead brother, that his name may not be blotted out from Israel\" — the levirate purpose: preserving the dead brother's name (<em>shem</em>) and inheritance-line within Israel. The fear of name-obliteration reflects the ancient understanding of death-in-memory as the continuation of existence: to have no name remembered is to be truly dead. The levirate is therefore a covenantal act of resurrection-by-memory: the dead man's line continues, his name lives. This concern for name-preservation echoes Isaiah 56:5's promise to eunuchs: \"I will give them an everlasting name that shall not be cut off\" — the new covenant provides the ultimate levirate, a name preserved forever in YHWH's own memory.</p>",
        "7": "<p>\"And if the man does not wish to take his brother's wife, then his brother's wife shall go up to the gate to the elders and say, 'My husband's brother refuses to perpetuate his brother's name in Israel; he will not perform the duty of a husband's brother to me'\" — the judicial process for levirate refusal: the widow brings the case to the elders. The law does not force the brother but creates a public process for declining the duty — which comes with public cost (the sandal-removal ceremony and the shaming of v9-10). The widow has legal agency to initiate the process, not merely to await the brother's decision.</p>",
        "8": "<p>\"Then the elders of his city shall call him and speak to him, and if he persists, saying, 'I do not wish to take her'\" — the elders' mediation: the community attempts persuasion before the public ceremony. The elders' role is pastoral before it is judicial: speaking to the reluctant brother, not immediately imposing the shame-ceremony. The law provides a pathway for declining that, while shameful, is nonetheless legal — the covenant does not impose absolute compulsion but does impose significant social cost for declining a covenant duty.</p>",
        "9": "<p>\"Then his brother's wife shall go up to him in the presence of the elders and pull his sandal off his foot and spit in his face. And she shall answer and say, 'So shall it be done to the man who does not build up his brother's house'\" — the <em>chalitzah</em> ceremony (sandal-removal): the public shaming of the brother who refuses levirate duty. The sandal removal reverses the sandal-ceremony of property transfer (Ruth 4:7-8: removing a sandal was the traditional way to confirm a transfer). The reversed ceremony (<em>she</em> removes <em>his</em> sandal) publicly withdraws him from his covenant responsibility. John 1:27: John the Baptist's statement that he is \"not worthy to untie the sandal\" of the one coming after him invokes this Deuteronomic sandal-language — the sandal is the symbol of standing, authority, and right of succession. John disclaims his own standing relative to Christ's.</p>",
        "10": "<p>\"And the name of his family shall be called in Israel, 'The house of him who had his sandal pulled off'\" — the permanent family-name consequence: the shame attaches not just to the individual but to his family line. The naming is the covenantal memory-consequence of failing covenant duty. The law creates communal accountability through naming: families are remembered by their covenant faithfulness or failure. The positive counterpart is Boaz's memorial: \"to perpetuate the name of the dead in his inheritance\" (Ruth 4:10) — Boaz takes the kinsman-redeemer role that the nearer kinsman declined (Ruth 4:6), and Boaz's name is preserved in the Messiah's genealogy (Matt 1:5).</p>",
        "11": "<p>\"When men fight with one another and the wife of the one draws near to rescue her husband from the hand of him who is beating him and puts out her hand and seizes him by his private parts\" — the fight-intervention scenario: a woman intervenes in a fight to protect her husband by grabbing the opponent's genitals. The legal scenario sets up the unusual penalty in v12. The extreme intervention represents a combination of intent (protecting her husband) and means (a method that requires specific legal address because of the social and physical implications).</p>",
        "12": "<p>\"Then you shall cut off her hand. Your eye shall have no pity\" — the hand-amputation penalty: the only explicit amputation penalty in the Torah. The combination of the body-part targeted (reproductive) and the penalty (hand) creates a proportional response in kind. The no-pity formula (<em>lo tachos einkha</em>) appears elsewhere for extreme violations that require full judicial consequence without sentiment. The law is rarely discussed and its application in Israel's legal history is uncertain — it may function as a maximum-deterrent rather than a regularly applied penalty.</p>",
        "13": "<p>\"You shall not have in your bag two kinds of weights, a large and a small\" — the honest-weights legislation (vv13-16): the false-weight prohibition. <em>Even vaeven</em> (weight and weight) — carrying two sets of weights (larger for buying, smaller for selling) is covenant fraud. Proverbs 11:1: \"A false balance is an abomination to the LORD, but a just weight is his delight.\" Amos 8:5: \"making the ephah small and the shekel great and dealing deceitfully with false balances\" — the prophetic indictment uses the Deuteronomic standard as the baseline for commercial ethics. The marketplace is a covenant space: the same integrity required in the courts is required in commerce.</p>",
        "14": "<p>\"You shall not have in your house two kinds of measures, a large and a small\" — the honest-measures extension: not just weights (for precious metals/grain by mass) but measures (for volume). The double prohibitions (weights and measures) cover all quantitative commercial transactions. The covenant's integrity-demand extends into every commercial interaction, not merely into formal legal proceedings.</p>",
        "15": "<p>\"A full and fair weight you shall have, a full and fair measure you shall have, that your days may be long in the land that the LORD your God is giving you\" — the positive formulation with life-extension promise: <em>even shlemah vatzedek yihye lach</em> (a full/whole and righteous weight shall you have). <strong>Shlem</strong> (whole, complete) and <strong>tzedek</strong> (righteous/just) are combined: commercial integrity is covenantal righteousness. The same life-extension promise attached to honoring parents (5:16) and bird-nest mercy (22:7) is here attached to honest commerce: the covenant weaves together family, ecological, and commercial ethics under the same blessing-logic.</p>",
        "16": "<p>\"For all who do such things, all who act dishonestly, are an abomination to the LORD your God\" — <em>toevat YHWH eloheicha</em>: the commercial fraudster commits the same category of covenant violation as the idolater. The <em>toevah</em> term marks commercial dishonesty as a first-order covenant issue, not a minor infraction. The God who is himself <em>emet</em> (truth/faithfulness) is offended by the false weight that contradicts truth in commercial exchange. Proverbs 16:11: \"A just balance and scales are the LORD's; all the weights in the bag are his work.\" The weights are under YHWH's direct sovereignty.</p>",
        "17": "<p>\"Remember what Amalek did to you on the way as you came out of Egypt\" — the Amalek-memory command (vv17-19): the counter-command to the general Egyptian non-abhorrence (23:7). Amalek attacked Israel at Rephidim unprovoked and specifically targeted the weak and weary at the rear (v18). The attack on the vulnerable is the defining feature that warrants permanent covenantal hostility. Numbers 24:20: Balaam's oracle — \"Amalek was the first among the nations, but its end is utter destruction.\" 1 Samuel 15: Saul's incomplete execution of the Amalek-command becomes the occasion for his rejection as king. The Amalek-command represents the theological problem of divine command for corporate destruction.</p>",
        "18": "<p>\"How he attacked you on the way when you were faint and weary, and cut off your tail, those who were lagging behind you, and he did not fear God\" — the specific indictment: Amalek attacked the weak stragglers — those least able to defend themselves. <em>Velo yare Elohim</em> (and he did not fear God): the absence of the fear of God is the theological diagnosis of Amalek's attack. Those who do not fear God attack the vulnerable; those who fear God protect them. The Deuteronomic ethics of vulnerable-protection (24:17-21) and the Amalek command share the same logic: Amalek is the anti-type of Deuteronomy's covenant ethics.</p>",
        "19": "<p>\"Therefore when the LORD your God has given you rest from all your enemies around you, in the land that the LORD your God is giving you for an inheritance to possess, you shall blot out the memory of Amalek from under heaven; you shall not forget\" — the Amalek-obliteration command: <em>timcheh et-zecher Amalek</em> (blot out the memory of Amalek). The irony of the command: \"blot out the memory\" + \"you shall not forget\" creates a permanent memorial of the obligation to destroy the memory. The command creates the very memory it seeks to eradicate. 1 Samuel 15's partial-execution by Saul and the subsequent Agag-execution by Samuel represent the covenant's insistence that divine commands be fully executed, not partially — a theme Paul uses in Galatians 3:10 (\"Cursed is everyone who does not abide by all things written in the Book of the Law, to do them\").</p>"
    }
}


def main():
    existing = load_comm("mkt-original", "deuteronomy")
    before = sum(len(v) for v in existing.values())
    merge_comm(existing, DEUT)
    after = sum(len(v) for v in existing.values())
    save_comm("mkt-original", "deuteronomy", existing)
    print(f"{len(existing)} chapters, {after} verse entries total (+{after - before} new)")
    for v, kw in [("1", "ignore"), ("7", "mother"), ("12", "tassels"), ("22", "adultery")]:
        entry = existing.get("22", {}).get(v, "MISSING")
        print(f"  Deut 22:{v} — {'OK' if kw.lower() in entry.lower() else 'CHECK'}")
    for v, kw in [("1", "eunuch"), ("15", "escaped slave"), ("19", "interest")]:
        entry = existing.get("23", {}).get(v, "MISSING")
        print(f"  Deut 23:{v} — {'OK' if kw.lower() in entry.lower() else 'CHECK'}")
    for v, kw in [("1", "divorce"), ("16", "individual"), ("19", "gleaning")]:
        entry = existing.get("24", {}).get(v, "MISSING")
        print(f"  Deut 24:{v} — {'OK' if kw.lower() in entry.lower() else 'CHECK'}")
    for v, kw in [("4", "muzzle"), ("5", "levirate"), ("17", "amalek")]:
        entry = existing.get("25", {}).get(v, "MISSING")
        print(f"  Deut 25:{v} — {'OK' if kw.lower() in entry.lower() else 'CHECK'}")
    for ch in ["22", "23", "24", "25"]:
        total = {"22": 30, "23": 25, "24": 22, "25": 19}[ch]
        present = len(existing.get(ch, {}))
        missing = [str(i) for i in range(1, total + 1) if str(i) not in existing.get(ch, {})]
        print(f"  Ch {ch}: {present}/{total} — missing: {missing if missing else 'none'}")


if __name__ == "__main__":
    main()
